#include<bits/stdc++.h>
using namespace std;
const int N=10010;
int dfn[N],low[N],dfncnt,id[N],siz[N],scccnt;
bool instk[N];
vector<int> mp[N];
stack<int> s;
vector<int> scc[N];
void tarjan(int x)
{
    dfn[x]=low[x]=++dfncnt;
    s.push(x);
    instk[x]=1;
    for(int v:mp[x])
    {
        if(dfn[v]==0)
        {
            tarjan(v);
            low[x]=min(low[x],low[v]);
        }
        else if(instk[v])
        {
            low[x]=min(low[x],dfn[v]);
        }
    }
    if(dfn[x]==low[x])
    {
        scccnt++;
        int top;
        do
        {
            top=s.top();
            instk[top]=0;
            siz[scccnt]++;
            scc[scccnt].push_back(top);
            id[top]=scccnt;
            s.pop();
        }while(top!=x);
    }
}
int main()
{
    int n,m;
    scanf("%d%d",&n,&m);
    for(int i=1;i<=m;i++)
    {
        int u,v;
        scanf("%d%d",&u,&v);
        mp[u].push_back(v);
    }
    for(int i=1;i<=n;i++)
    {
        if(!dfn[i])
        {
            tarjan(i);
        }
    }
    printf("%d\n",scccnt);
    for(int i=1;i<=n;i++)
    {
        if(siz[id[i]]!=0)
        {
            siz[id[i]]=0;
            sort(scc[id[i]].begin(),scc[id[i]].end());
            for(int j:scc[id[i]])
            {
                printf("%d ",j);
            }
            printf("\n");
        }
    }
    return 0;
}
